<?php namespace App\Repositories\FrontOffice;use App\Repositories\BaseRepository;use App\Models\FrontOffice\CallLog;use Illuminate\Database\Eloquent\Collection;class CallLogRepository extends BaseRepository{    public function __construct(CallLog $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByCallType(string $callType): Collection    {        return $this->findByField('call_type', $callType);    }    public function findByDirection(string $direction): Collection    {        return $this->findByField('direction', $direction);    }    public function getByDate(string $date): Collection    {        return $this->query()->whereDate('call_date', $date)->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('call_date', [$startDate, $endDate])->get();    }    public function searchCallLogs(string $keyword): Collection    {        return $this->query()->where('caller_name', 'like', "%{$keyword}%")->orWhere('caller_phone', 'like', "%{$keyword}%")->orWhere('purpose', 'like', "%{$keyword}%")->orWhere('notes', 'like', "%{$keyword}%")->get();    }    public function getTodayCalls(): Collection    {        return $this->query()->whereDate('call_date', now())->get();    }    public function getByReceivedBy(int $userId): Collection    {        return $this->findByField('received_by', $userId);    }    public function getFollowUpRequired(): Collection    {        return $this->query()->where('follow_up_required', true)->where('status', 'pending')->get();    }    public function markCompleted(int $id): bool    {        return $this->update($id, ['status' => 'completed']);    }}